46	    void write(String id, String summaryJson, String title) throws IOException {
47	        Files.createDirectories(dir);
48	        Files.writeString(file(id, ".summary.json"), summaryJson);
49	        // The short title is best-effort and must not fail the summary cache write.
50	        if (title != null && !title.isBlank()) {
51	            try {
52	                Files.writeString(file(id, ".short_title.txt"), title.trim());
