33	    /** The flavor used when none is supplied. */
34	    static final String DEFAULT_FLAVOR = "antigravity-cli";
35	
36	    private static final String LOGS_DIR = ".system_generated";
37	    private static final String LOGS_SUBDIR = "logs";
38	    private static final String TRANSCRIPT = "transcript.jsonl";
39	    private static final String TRANSCRIPT_FULL = "transcript_full.jsonl";
40	    private static final String SUMMARY_JSON = "summary.json";
