49	    static Path brainDir(String flavor) {
50	        String dir = (flavor == null || flavor.isEmpty()) ? DEFAULT_FLAVOR : flavor;
51	        return geminiRoot().resolve(dir).resolve("brain");
52	    }
53	
54	    /** The generated-logs directory inside a given session directory. */
55	    static Path logsDir(Path sessionDir) {
