252	
253	                    // Keep the progress bar moving smoothly during the long final LLM consolidation
254	                    AtomicBoolean consolidationDone = new AtomicBoolean(false);
255	                    Future<?> fakeProgress = executor.submit(() -> {
256	                        int p = 90;
257	                        while (!consolidationDone.get() && p < 99) {
