16	package io.github.glaforge.agybrainviz;
17	
18	import io.micronaut.runtime.Micronaut;
19	import java.util.Locale;
20	import java.util.Map;
21	
22	public class Application {
23	
24	    public static void main(String[] args) {
25	        for (String arg : args) {
26	            if ("-h".equals(arg) || "--help".equals(arg)) {
27	                printHelp();
28	                System.exit(0);
29	            } else if ("-v".equals(arg) || "--version".equals(arg)) {
30	                System.out.println("Agent Brain Visualizer version " + Version.VERSION);
31	                System.exit(0);
32	            }
33	        }
34	        applyDotEnvFrameworkSettings();
35	        applyDatasourceSettings(DotEnv.values());
36	        Micronaut.run(Application.class, args);
37	    }
38	
39	    /**
40	     * Maps the store's connection settings onto Micronaut's {@code datasources.default} properties.
41	     * Unlike {@code MICRONAUT_*}, these names don't correspond to a framework property, so a real
42	     * {@code DATABASE_URL} environment variable has to be bridged explicitly too — not just the
43	     * {@code .env} entries. Precedence stays the same: real environment variable, then {@code .env},
44	     * and an explicit {@code -D} flag beats both. Values left unset fall through to the defaults in
45	     * {@code application.yml}, which match {@code docker-compose.yml}.
46	     */
47	    static void applyDatasourceSettings(Map<String, String> dotEnvValues) {
48	        applyDatasourceSetting("DATABASE_URL", "datasources.default.url", dotEnvValues);
49	        applyDatasourceSetting("POSTGRES_USER", "datasources.default.username", dotEnvValues);
50	        applyDatasourceSetting("POSTGRES_PASSWORD", "datasources.default.password", dotEnvValues);
51	    }
52	
53	    /** The pure half of {@link #applyDatasourceSettings}, so the precedence rules are testable. */
54	    static void applyDatasourceSetting(
55	        String key,
56	        String property,
57	        Map<String, String> dotEnvValues
58	    ) {
59	        String value = System.getenv(key);
60	        if (value == null) value = dotEnvValues.get(key);
61	        // A blank value would fail Micronaut's property resolution; leave the yml default in place.
62	        if (value == null || value.isBlank()) return;
63	        if (System.getProperty(property) == null) { // an explicit -D flag wins
64	            System.setProperty(property, value);
65	        }
66	    }
67	
68	    /**
69	     * Feeds {@code MICRONAUT_*} entries from a {@code .env} file into system properties (e.g.
70	     * {@code MICRONAUT_SERVER_PORT} → {@code micronaut.server.port}) so the framework honours them.
71	     * Real environment variables and explicit {@code -D} flags take precedence over the file. The AI
72	     * settings are read separately by {@link AiConfig}.
73	     */
74	    private static void applyDotEnvFrameworkSettings() {
75	        applyFrameworkSettings(DotEnv.values());
76	    }
77	
78	    /** The pure half of {@link #applyDotEnvFrameworkSettings()}, so the precedence rules are testable. */
79	    static void applyFrameworkSettings(Map<String, String> values) {
80	        for (Map.Entry<String, String> entry : values.entrySet()) {
81	            String key = entry.getKey();
82	            String value = entry.getValue();
83	            if (!key.startsWith("MICRONAUT_")) continue;
84	            // A blank value would fail Micronaut's property resolution; ignore the line instead.
85	            if (value == null || value.isBlank()) continue;
86	            if (System.getenv(key) != null) continue; // a real environment variable wins
87	            String property = key.toLowerCase(Locale.ROOT).replace('_', '.');
88	            if (System.getProperty(property) == null) { // an explicit -D flag wins
89	                System.setProperty(property, value);
