16	package io.github.glaforge.agybrainviz;
17	
18	import jakarta.inject.Singleton;
19	import java.sql.Connection;
20	import java.sql.PreparedStatement;
21	import java.sql.ResultSet;
22	import java.sql.SQLException;
23	import java.sql.Timestamp;
24	import java.sql.Types;
25	import java.util.LinkedHashMap;
26	import java.util.Map;
27	import javax.sql.DataSource;
28	
29	/**
30	 * Reads and writes ingested trajectories, keyed by the stable {@code (source, id)} pair.
31	 *
32	 * <p>That key is the whole de-duplication mechanism: the id is derived from the trajectory itself
33	 * (a Claude Code session UUID, a Codex rollout id, an Antigravity session directory), never from the
34	 * path it was found at. So the same session pushed from two machines, or pushed twice from one,
35	 * lands on exactly one row.
36	 */
37	@Singleton
38	public class SessionRepository {
39	
40	    // The `WHERE content_hash <> excluded.content_hash` guard is what makes re-pushing an unchanged
41	    // trajectory a no-op: the row is left alone and executeUpdate reports 0.
42	    private static final String UPSERT_SQL = """
43	        INSERT INTO sessions (source, id, title, updated_at, steps, content_hash, source_mtime)
44	        VALUES (?, ?, ?, ?, ?::jsonb, ?, ?)
45	        ON CONFLICT (source, id) DO UPDATE
46	           SET title = excluded.title,
47	               updated_at = excluded.updated_at,
48	               steps = excluded.steps,
49	               content_hash = excluded.content_hash,
50	               source_mtime = excluded.source_mtime,
51	               ingested_at = now()
52	         WHERE sessions.content_hash <> excluded.content_hash
53	        """;
54	
55	    private static final String MANIFEST_SQL =
56	        "SELECT id, content_hash FROM sessions WHERE source = ?";
57	
58	    private static final String COUNT_SQL = "SELECT count(*) FROM sessions WHERE source = ?";
59	
60	    private final DataSource dataSource;
61	
62	    public SessionRepository(DataSource dataSource) {
63	        this.dataSource = dataSource;
64	    }
65	
66	    /** One ingested trajectory, as pushed by a client and normalized by the server. */
67	    public record Session(
68	        String source,
69	        String id,
70	        String title,
71	        long sourceMtime,
72	        String stepsJson,
73	        String contentHash
74	    ) {}
75	
76	    /**
77	     * Inserts the session, or updates it when its content changed.
78	     *
79	     * @return whether a row was written; {@code false} means an identical trajectory was already
80	     *     stored, so this push was a no-op.
81	     */
82	    public boolean upsert(Session session) {
83	        try (
84	            Connection connection = dataSource.getConnection();
85	            PreparedStatement stmt = connection.prepareStatement(UPSERT_SQL)
86	        ) {
87	            stmt.setString(1, session.source());
88	            stmt.setString(2, session.id());
89	            stmt.setString(3, session.title());
90	            stmt.setTimestamp(4, new Timestamp(session.sourceMtime()));
91	            stmt.setObject(5, session.stepsJson(), Types.OTHER);
92	            stmt.setString(6, session.contentHash());
93	            stmt.setLong(7, session.sourceMtime());
94	            return stmt.executeUpdate() > 0;
95	        } catch (SQLException e) {
96	            throw new StoreUnavailableException("Could not store session " + session.id(), e);
97	        }
98	    }
99	
100	    /**
101	     * @return every stored {@code id -> contentHash} for a source, so a client can skip pushing the
102	     *     trajectories that have not changed. Sending the hashes rather than the transcripts is what
103	     *     keeps a sync cheap once the corpus is large.
104	     */
105	    public Map<String, String> manifest(String source) {
106	        Map<String, String> manifest = new LinkedHashMap<>();
107	        try (
108	            Connection connection = dataSource.getConnection();
109	            PreparedStatement stmt = connection.prepareStatement(MANIFEST_SQL)
110	        ) {
111	            stmt.setString(1, source);
112	            try (ResultSet rs = stmt.executeQuery()) {
113	                while (rs.next()) manifest.put(rs.getString("id"), rs.getString("content_hash"));
114	            }
115	        } catch (SQLException e) {
116	            throw new StoreUnavailableException("Could not read the manifest for " + source, e);
117	        }
118	        return manifest;
119	    }
120	
121	    /** @return how many trajectories are stored for a source. */
122	    public int countBySource(String source) {
123	        try (
124	            Connection connection = dataSource.getConnection();
125	            PreparedStatement stmt = connection.prepareStatement(COUNT_SQL)
126	        ) {
127	            stmt.setString(1, source);
128	            try (ResultSet rs = stmt.executeQuery()) {
129	                return rs.next() ? rs.getInt(1) : 0;
130	            }
131	        } catch (SQLException e) {
132	            throw new StoreUnavailableException("Could not count sessions for " + source, e);
133	        }
134	    }
135	}

