50	
51	    /** Stores a batch, counting each trajectory as ingested, skipped (unchanged), or failed. */
52	    public IngestResult ingest(List<IngestSession> batch) {
53	        int ingested = 0;
54	        int skipped = 0;
55	        int failed = 0;
56	        for (IngestSession pushed : batch == null ? List.<IngestSession>of() : batch) {
57	            switch (store(pushed)) {
58	                case INGESTED -> ingested++;
59	                case SKIPPED -> skipped++;
60	                case FAILED -> failed++;
61	            }
62	        }
63	        return new IngestResult(ingested, skipped, failed);
64	    }
65	
66	    private enum Outcome {
67	        INGESTED,
68	        SKIPPED,
69	        FAILED,
70	    }
71	
72	    private Outcome store(IngestSession pushed) {
73	        if (pushed == null || isBlank(pushed.id()) || isBlank(pushed.source())) {
74	            LOG.warn("Rejecting a pushed trajectory with no source or id");
75	            return Outcome.FAILED;
76	        }
77	        Optional<SourceNormalizer> normalizer = normalizerFor(pushed.source());
78	        if (normalizer.isEmpty()) {
79	            LOG.warn("Rejecting trajectory {}: unknown source '{}'", pushed.id(), pushed.source());
80	            return Outcome.FAILED;
81	        }
82	
83	        String raw = pushed.raw() == null ? "" : pushed.raw();
84	        List<String> lines = raw.lines().toList();
85	        String stepsJson = normalizer.get().toStepsJson(lines);
86	        String title = titleFor(pushed, normalizer.get(), lines);
87	
88	        // A pushed mtime of 0 (a client that could not stat the file) would sort the session to the
89	        // epoch; treat it as "now" so it still appears at the top of a newest-first listing.
90	        long mtime = pushed.sourceMtime() > 0 ? pushed.sourceMtime() : System.currentTimeMillis();
91	
92	        boolean written = sessions.upsert(
93	            new SessionRepository.Session(
94	                pushed.source(),
95	                pushed.id(),
96	                title,
97	                mtime,
98	                stepsJson,
99	                sha256(raw)
100	            )
101	        );
102	        return written ? Outcome.INGESTED : Outcome.SKIPPED;
103	    }
104	
105	    private Optional<SourceNormalizer> normalizerFor(String source) {
106	        return normalizers.stream().filter(n -> n.handles(source)).findFirst();
107	    }
108	
109	    // The client's title wins, then whatever the transcript reveals, then a stable last resort — the
110	    // session list must never show a blank row.
111	    private String titleFor(IngestSession pushed, SourceNormalizer normalizer, List<String> lines) {
112	        if (!isBlank(pushed.title())) return pushed.title().trim();
113	        return normalizer
114	            .deriveTitle(lines)
115	            .filter(t -> !t.isBlank())
116	            .orElseGet(() -> pushed.source() + " session " + shortId(pushed.id()));
117	    }
118	
119	    private static String shortId(String id) {
120	        return id.length() > 8 ? id.substring(0, 8) : id;
121	    }
122	
123	    /** Hex SHA-256 of the transcript's UTF-8 bytes. Clients hash the file the same way. */
124	    static String sha256(String raw) {
125	        try {
126	            MessageDigest digest = MessageDigest.getInstance("SHA-256");
127	            return HexFormat.of().formatHex(digest.digest(raw.getBytes(StandardCharsets.UTF_8)));
128	        } catch (NoSuchAlgorithmException e) {
129	            throw new IllegalStateException("SHA-256 is required by every JVM", e);
130	        }
131	    }
132	
133	    private static boolean isBlank(String value) {
134	        return value == null || value.isBlank();
135	    }
136	}

54	    public HttpResponse<?> guard(HttpRequest<?> request) {
55	        Optional<String> expected = config.token();
56	        if (expected.isEmpty()) return null; // unguarded by configuration
57	
58	        String header = request.getHeaders().get(HttpHeaders.AUTHORIZATION);
59	        if (header == null || !header.startsWith(BEARER) || !matches(expected.get(), header)) {
60	            return HttpResponse
61	                .unauthorized()
62	                .body(
63	                    Map.of("error", "Ingest requires a valid Authorization: Bearer <INGEST_TOKEN>.")
64	                );
65	        }
66	        return null;
67	    }
68	
69	    // Compare without leaking the token's length or contents through timing.
70	    private static boolean matches(String expected, String header) {
71	        byte[] presented = header
72	            .substring(BEARER.length())
73	            .trim()
74	            .getBytes(StandardCharsets.UTF_8);
75	        return MessageDigest.isEqual(expected.getBytes(StandardCharsets.UTF_8), presented);
76	    }
77	}

