304	// report accumulates per-source and total counts and renders the summary.
305	type report struct {
306		dryRun bool
307		order  []string
308		perSrc map[string]client.Result
309		total  client.Result
310	}
311	
312	func newReport(dryRun bool) *report {
313		return &report{dryRun: dryRun, perSrc: map[string]client.Result{}}
314	}
315	
316	func (r *report) add(source string, res client.Result) {
317		if _, seen := r.perSrc[source]; !seen {
318			r.order = append(r.order, source)
319		}
320		r.perSrc[source] = res
321		r.total.Ingested += res.Ingested
322		r.total.Skipped += res.Skipped
323		r.total.Failed += res.Failed
324	}
325	
326	func (r *report) write(stdout io.Writer, jsonOut bool) {
327		if jsonOut {
328			payload := map[string]any{
329				"dryRun":  r.dryRun,
330				"total":   r.total,
331				"sources": r.perSrc,
332			}
333			enc := json.NewEncoder(stdout)
334			enc.SetIndent("", "  ")
335			_ = enc.Encode(payload)
336			return
337		}
338	
339		if len(r.order) == 0 {
340			fmt.Fprintln(stdout, "No sessions found to ingest.")
341			return
342		}
343		verb := "ingested"
344		if r.dryRun {
345			verb = "would ingest"
346		}
347		width := 0
348		for _, s := range r.order {
349			width = max(width, len(s))
350		}
351		for _, s := range r.order {
352			res := r.perSrc[s]
353			fmt.Fprintf(stdout, "%-*s  %d %s, %d skipped, %d failed\n", width, s, res.Ingested, verb, res.Skipped, res.Failed)
354		}
355		fmt.Fprintf(stdout, "%-*s  %d %s, %d skipped, %d failed\n", width, "total", r.total.Ingested, verb, r.total.Skipped, r.total.Failed)
356	}
